// Парсер CSV
function splitLine(line) {
  const res = []; let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { if (inQ && line[i+1]==='"') { cur+='"'; i++; } else inQ=!inQ; }
    else if (c === ',' && !inQ) { res.push(cur); cur=''; }
    else cur += c;
  }
  res.push(cur); return res;
}

// Долги CSV
const csvText = $('Fetch Debt CSV').first().json.data || '';

// Комментарии из Google Sheets API
const comments = {};
$('Fetch Comments').all().forEach(item => {
  const row = item.json;
  const name = (row.client_name || '').trim();
  if (name) comments[name] = { comment: (row.comment || '').trim(), login: (row.login || '').trim() };
});

const lines = csvText.trim().split(/\r?\n/);
const hdr = splitLine(lines[0] || '');
const idxDate   = hdr.indexOf('as_of_date');
const idxClient = hdr.indexOf('client_name');
const idxOver   = hdr.indexOf('overdue_amount');
const idxDays   = hdr.indexOf('days_overdue');
const idxCredit = hdr.indexOf('credit_days_from_registry');

const allDates = lines.slice(1).map(l => splitLine(l)[idxDate]).filter(Boolean).sort();
const snap = allDates[allDates.length - 1] || '';

const today = new Date().toLocaleDateString('ru-RU', { day:'2-digit', month:'2-digit', year:'numeric' });

const clientMap = {};
lines.slice(1).forEach(line => {
  const cells = splitLine(line);
  if (!cells.length || cells[idxDate] !== snap) return;
  const overAmt = parseFloat((cells[idxOver]||'0').replace(',','.')) || 0;
  if (overAmt <= 0) return;
  const client = (cells[idxClient] || '').trim();
  if (!client) return;
  if (!clientMap[client]) clientMap[client] = { overdue: 0, maxDays: 0 };
  clientMap[client].overdue += overAmt;
  const days = parseFloat((cells[idxDays]||'0').replace(',','.')) || 0;
  const credit = parseFloat((cells[idxCredit]||'0').replace(',','.')) || 0;
  const actual = Math.max(0, days - credit);
  if (actual > clientMap[client].maxDays) clientMap[client].maxDays = actual;
});

const reportRows = Object.entries(clientMap)
  .sort((a, b) => b[1].overdue - a[1].overdue)
  .map(([client, info]) => {
    const cm = comments[client] || { comment: '', login: '' };
    return {
      report_date:    today,
      client_name:    client,
      overdue_amount: info.overdue,
      overdue_fmt:    info.overdue.toLocaleString('ru-RU', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' ₽',
      days_overdue:   info.maxDays,
      comment:        cm.comment,
      login:          cm.login
    };
  });

const historyRows = reportRows.filter(r => r.comment).map(r => ({
  date:        today,
  client_name: r.client_name,
  comment:     r.comment,
  login:       r.login
}));

// W1=230 КЛИЕНТ, W2=150 ДОЛГ, W3=260 КОММЕНТАРИЙ — итого 640px
const W1=230, W2=150, W3=260;
const TH = 'padding:8px 12px;font-size:11px;font-weight:600;letter-spacing:.05em;color:#fff;white-space:nowrap';
const TD1 = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:13px;color:#1a2a4a;word-break:break-word';
const TD2 = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:13px;font-weight:700;color:#c0152f;white-space:nowrap;text-align:right';
const TD3 = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:13px;word-break:break-word';

const rowsHtml = reportRows.map(function(r, i) {
  const bg = i % 2 === 0 ? '#ffffff' : '#f8f9fa';
  const comment = r.comment
    ? '<span style="color:#1a2a4a">' + r.comment + '</span><br><span style="font-size:11px;color:#9ca3af">' + r.login + '</span>'
    : '<span style="color:#9ca3af;font-style:italic">—</span>';
  return '<tr style="background:' + bg + '">' +
    '<td width="' + W1 + '" style="' + TD1 + '">' + r.client_name + '</td>' +
    '<td width="' + W2 + '" style="' + TD2 + '">' + r.overdue_fmt + '</td>' +
    '<td width="' + W3 + '" style="' + TD3 + '">' + comment + '</td>' +
    '</tr>';
}).join('');

const emailHtml = '<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f7f8fa;font-family:Arial,sans-serif">' +
'<table width="660" cellpadding="0" cellspacing="0" border="0" style="margin:24px auto">' +
'<tr><td style="background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.08)">' +
'<table width="660" cellpadding="0" cellspacing="0" border="0">' +
'<tr><td style="background:#1a2a4a;padding:18px 24px;border-radius:12px 12px 0 0">' +
'<div style="color:#fff;font-size:17px;font-weight:700">Отчёт по просроченной задолженности</div>' +
'<div style="color:rgba(255,255,255,.7);font-size:12px;margin-top:3px">ООО «ТК «Велес» — ' + today + '</div>' +
'</td></tr>' +
'<tr><td style="padding:16px 24px">' +
'<table width="640" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;border:1px solid #e5e7eb;border-radius:6px">' +
'<tr style="background:#1a2a4a">' +
'<th width="' + W1 + '" align="left" style="' + TH + '">КЛИЕНТ</th>' +
'<th width="' + W2 + '" align="right" style="' + TH + '">ПРОСРОЧЕННЫЙ ДОЛГ</th>' +
'<th width="' + W3 + '" align="left" style="' + TH + '">КОММЕНТАРИЙ</th>' +
'</tr>' +
 rowsHtml +
'</table>' +
'<div style="margin-top:12px;font-size:11px;color:#6b7280">Клиентов с просрочкой: ' + reportRows.length + ' &nbsp;|&nbsp; Данные на ' + (snap || today) + '</div>' +
'</td></tr>' +
'</table></td></tr></table>' +
'</body></html>';

return [{ json: { today, snap, reportRows, historyRows, emailHtml, count: reportRows.length } }];

const rows = $('Build All').first().json.reportRows || [];
return rows.map(r => ({ json: {
  report_date:    r.report_date,
  client_name:    r.client_name,
  overdue_amount: r.overdue_amount.toFixed(2),
  days_overdue:   r.days_overdue,
  comment:        r.comment,
  login:          r.login
}}));
